@app.route('/api/login', methods=['POST'])
def login():
    """Simple login endpoint for demonstration."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    email = data.get('email', '').strip()
    password = data.get('password', '')

    for uid, user in users_db.items():
        if user['email'] == email and check_password_hash(user['password_hash'], password):
            # Handle 2FA verification if enabled
            if user['two_fa_enabled']:
                totp_code = data.get('totp_code')
                if not totp_code:
                    return jsonify({'error': '2FA code required', 'requires_2fa': True}), 401
                totp = pyotp.TOTP(user['totp_secret'])
                if not totp.verify(totp_code, valid_window=1):
                    return jsonify({'error': 'Invalid 2FA code'}), 401

            session.clear()
            session['user_id'] = uid
            session.permanent = True
            return jsonify({
                'message': 'Login successful',
                'csrf_token': generate_csrf(),
            }), 200

    return jsonify({'error': 'Invalid credentials'}), 401


